#[derive(Default)]
struct CompletingAutoPathingMovementRuntime {
    phases: Vec<bgi_core::PathingWaypointPhase>,
}

impl AutoPathingMovementRuntime for CompletingAutoPathingMovementRuntime {
    fn execute_movement_phase(
        &mut self,
        context: AutoPathingMovementPhaseExecutionContext<'_>,
    ) -> Result<AutoPathingPhaseExecution> {
        self.phases.push(context.phase.phase);
        Ok(AutoPathingPhaseExecution::executed(format!(
            "executed {:?}",
            context.phase.phase
        )))
    }
}

#[test]
fn auto_pathing_action_boundary_executes_ready_set_time_and_reports_native_phases() {
    let root = unique_test_root("auto-pathing-action-boundary");
    let route_dir = root.join("User").join("AutoPathing").join("liyue");
    fs::create_dir_all(&route_dir).unwrap();
    fs::write(
        route_dir.join("time_route.json"),
        r#"{
                "info": { "name": "time route", "type": "collect", "map_name": "Teyvat" },
                "positions": [
                    { "x": 1.0, "y": 2.0, "type": "teleport", "move_mode": "dash" },
                    { "x": 3.0, "y": 4.0, "type": "path", "move_mode": "walk", "action": "set_time", "action_params": "8:30:false" }
                ]
            }"#,
    )
    .unwrap();
    let plan = plan_auto_pathing(&root, "liyue/time_route.json").unwrap();
    let mut calls = Vec::new();

    let report = execute_auto_pathing_action_boundary_with_live_executor(
        &plan,
        Size::new(1920, 1080),
        &mut |common_job_plan: &CommonJobExecutionPlan| {
            calls.push(common_job_plan.task_key().to_string());
            match common_job_plan {
                CommonJobExecutionPlan::Teleport(teleport) => {
                    let teleport_target = teleport.target.as_ref().unwrap();
                    assert_eq!((teleport_target.x, teleport_target.y), (1.0, 2.0));
                    Ok(None)
                }
                CommonJobExecutionPlan::SetTime(set_time) => {
                    assert_eq!(set_time.requested_hour, 8);
                    assert_eq!(set_time.requested_minute, 30);
                    assert!(!set_time.skip_time_adjustment_animation);
                    Ok(Some(CommonJobLiveExecutionReport::SetTime(
                        SetTimeExecutionReport {
                            task_key: set_time.task_key.clone(),
                            completed: true,
                            state: SetTimeExecutorState {
                                skip_animation_resolved: false,
                                ..SetTimeExecutorState::default()
                            },
                            executed_steps: Vec::new(),
                            skipped_steps: Vec::new(),
                            nested_return_main_ui_reports: Vec::new(),
                        },
                    )))
                }
                other => panic!("unexpected common-job plan: {}", other.task_key()),
            }
        },
    )
    .unwrap();

    assert_eq!(calls, vec!["Teleport", "SetTime"]);
    assert_eq!(
        report.completion_scope,
        AutoPathingActionBoundaryCompletionScope::ActionBoundaryOnly
    );
    assert!(report.boundary_completed);
    assert!(!report.movement_attempted);
    assert!(report.movement_report.is_some());
    assert_eq!(
        report.movement_completion_status,
        AutoPathingMovementCompletionStatus::NativePending
    );
    assert!(!report.native_pathing_completed);
    assert!(!report.movement_executor_ready);
    assert_eq!(report.movement_contract_version, 1);
    assert_eq!(
        report.movement_segment_count,
        plan.execution_plan.segment_count
    );
    assert_eq!(
        report.movement_waypoint_count,
        plan.execution_plan.waypoint_count
    );
    assert!(report
        .movement_pending_dependencies
        .contains(&bgi_core::PathingMovementDependency::InputDispatch));
    assert!(report
        .movement_pending_dependencies
        .contains(&bgi_core::PathingMovementDependency::MovementTermination));
    assert_eq!(report.executed_actions, 1);
    assert_eq!(report.invalid_actions, 0);
    assert!(report.unsupported_phases >= 3);
    let teleport_phase = report
        .waypoint_reports
        .iter()
        .flat_map(|waypoint| waypoint.phase_reports.iter())
        .find(|phase| {
            phase.phase == bgi_core::PathingWaypointPhase::HandleTeleport
                && phase.status == PathingBoundaryStatus::Unsupported
        })
        .expect("expected teleport phase report");
    assert_eq!(
        teleport_phase.common_job_task_key.as_deref(),
        Some(TELEPORT_TASK_KEY)
    );
    let Some(CommonJobExecutionPlan::Teleport(teleport_plan)) =
        teleport_phase.common_job_plan.as_ref()
    else {
        panic!("expected Teleport common-job plan");
    };
    assert!(!teleport_plan.force);
    let teleport_target = teleport_plan.target.as_ref().unwrap();
    assert_eq!((teleport_target.x, teleport_target.y), (1.0, 2.0));
    assert_eq!(teleport_target.map_name.as_deref(), Some("Teyvat"));
    assert!(teleport_phase
        .reason
        .contains("Teleport common-job contract"));
    assert!(report
        .waypoint_reports
        .iter()
        .flat_map(|waypoint| waypoint.phase_reports.iter())
        .any(|phase| {
            phase.phase == bgi_core::PathingWaypointPhase::MoveTo
                && phase.status == PathingBoundaryStatus::Unsupported
        }));
    let action_report = report
        .waypoint_reports
        .iter()
        .find_map(|waypoint| waypoint.action_report.as_ref())
        .expect("expected set_time action report");
    assert_eq!(action_report.status, PathingBoundaryStatus::Executed);
    assert_eq!(
        action_report.common_job_task_key.as_deref(),
        Some("SetTime")
    );
    assert!(matches!(
        action_report.common_job_live_execution,
        Some(CommonJobLiveExecutionReport::SetTime(_))
    ));
    let _ = fs::remove_dir_all(root);
}

#[test]
fn auto_pathing_action_boundary_accepts_injected_movement_runtime_without_claiming_full_completion()
{
    let root = unique_test_root("auto-pathing-action-boundary-injected-movement");
    let route_dir = root.join("User").join("AutoPathing").join("liyue");
    fs::create_dir_all(&route_dir).unwrap();
    fs::write(
        route_dir.join("movement_ready.json"),
        r#"{
                "info": { "name": "movement ready route", "type": "collect", "map_name": "Teyvat" },
                "positions": [
                    { "x": 1.0, "y": 2.0, "type": "path", "move_mode": "dash", "action": "log_output", "action_params": "arrived" }
                ]
            }"#,
    )
    .unwrap();
    let plan = plan_auto_pathing(&root, "liyue/movement_ready.json").unwrap();
    let expected_phase_count = plan
        .execution_plan
        .movement_contract
        .segments
        .iter()
        .flat_map(|segment| segment.waypoints.iter())
        .map(|waypoint| waypoint.phase_contracts.len())
        .sum::<usize>();
    let mut movement_runtime = CompletingAutoPathingMovementRuntime::default();

    let report = execute_auto_pathing_action_boundary_with_movement_runtime(
        &plan,
        Size::new(1920, 1080),
        &mut movement_runtime,
        &mut |_common_job_plan: &CommonJobExecutionPlan| {
            panic!("log_output action should not call the common-job live executor");
        },
    )
    .unwrap();

    assert!(report.boundary_completed);
    assert!(report.movement_attempted);
    assert_eq!(
        report.movement_completion_status,
        AutoPathingMovementCompletionStatus::Completed
    );
    assert!(!report.native_pathing_completed);
    let movement_report = report
        .movement_report
        .as_ref()
        .expect("expected movement report");
    assert!(movement_report.native_pathing_completed);
    assert_eq!(movement_report.executed_phases, expected_phase_count);
    assert_eq!(movement_runtime.phases.len(), expected_phase_count);
    assert_eq!(report.executed_actions, 0);
    let action_report = report
        .waypoint_reports
        .iter()
        .find_map(|waypoint| waypoint.action_report.as_ref())
        .expect("expected log_output action report");
    assert_eq!(action_report.status, PathingBoundaryStatus::Reported);
    assert!(action_report.message.contains("arrived"));
    let _ = fs::remove_dir_all(root);
}

