    assert_eq!(statue.kind, TeleportPlanKind::StatueOfTheSeven);
    assert_eq!(statue.target, None);
    assert!(statue
        .steps
        .iter()
        .any(|step| matches!(&step.action, TeleportStepAction::SelectStatueOfTheSeven)));

    let missing_x = serde_json::json!({ "y": 2.0 });
