    set_relogin_retry_attempts(&mut plan, 9, 1);
    let mut runtime =
        RecordingCommonJobRuntime::with_locator_matches([false, false, true, true, true, false]);

    let report = execute_relogin_plan(&plan, &mut runtime).unwrap();

